from __future__ import annotations

import time


class ConnectionPool:
    def __init__(self, factory, *, max_size: int, now=None):
        if max_size <= 0:
            raise ValueError('max_size must be positive')
        self.factory = factory
        self.max_size = max_size
        self.now = now or time.monotonic
        self.idle = []

    def acquire(self):
        if len(self.idle) > 0:
            return self.idle.pop()[0]
        return self.factory()

    def release(self, conn):
        if len(self.idle) < self.max_size:
            self.idle.append((conn, self.now()))
        elif hasattr(conn, 'close'):
            conn.close()

    def evict_idle(self, max_idle_seconds: float):
        current = self.now()
        new_idle = []
        for conn, stamp in self.idle:
            if current - stamp > max_idle_seconds:
                if hasattr(conn, 'close'):
                    conn.close()
            else:
                new_idle.append((conn, stamp))
        self.idle = new_idle

